head.script:
// Set title dynamically after window.ByVendors loads
window.addEventListener("DOMContentLoaded", function () {
  if (window.ByVendors && window.ByVendors.byMetas) {
    const brandName =
      window.ByVendors.byMetas.BRAND_NAME_FIRST_CHAR_UPPER;
    if (brandName) {
      document.title =
        "Buy & Sell Bitcoin, Ether | Cryptocurrency Exchange | " +
        brandName;
    }
  }

  // Set logo dynamically based on REGULATED_SITE_HOSTS
  if (window.ByVendors && window.ByVendors.byEnv) {
    const logoImg = document.getElementById("logoimg");
    if (logoImg) {
      const isUSA = window.ByVendors.byEnv.REGULATED_SITE_HOSTS === "USA";
      const basePath = "/common-static/frontend-web/final-page/";
      logoImg.src = isUSA
        ? basePath + "logo_usa.svg"
        : basePath + "logo.svg";
    }
  }
});
